qry:select.qry:xquery:
			for $r in sql('
			SELECT
				SEL02_REQ.oi_req, 
				SEL02_REQ.c_req, 
				SEL02_REQ.d_req, 
        SEL02_REQ.f_req,
				SEL02_REQ.ca_estado
			FROM 
				SEL02_REQ
			WHERE
				SEL02_REQ.oi_empresa = {%= #SOURCE:@oi_empresa %}
				{%? (#FILTRO:@oi_req!='') {% AND SEL02_REQ.oi_req={#FILTRO:@oi_req} %} {% %} %}
				{%? (#FILTRO:@f_desde_req!='') {% AND SEL02_REQ.f_req >= {#FILTRO:@f_desde_req} %} {% %} %}
				{%? (#FILTRO:@f_hasta_req!='') {% AND SEL02_REQ.f_req <={#FILTRO:@f_hasta_req} %} {% %} %}
				{%? (#FILTRO:@ca_estado_req!='') {% AND SEL02_REQ.ca_estado={#FILTRO:@ca_estado_req} %} {% %} %}
    ')/ROWS/ROW
